 namespace WPAICG\Includes\DependencyLoaders; if (!defined('ABSPATH')) { exit; } class Woocommerce_Writer_Loader { public static function load() { add_action('plugins_loaded', [__CLASS__, 'init_integrations']); } public static function init_integrations() { if (!class_exists('WooCommerce')) { return; } $woo_base_path = WPAICG_PLUGIN_DIR . 'classes/woocommerce/'; $woo_integration_path = $woo_base_path . 'class-aipkit-woocommerce-integration.php'; if (file_exists($woo_integration_path)) { require_once $woo_integration_path; \WPAICG\WooCommerce\AIPKit_WooCommerce_Integration::get_instance(); } } } 